import novamind_api as nm
from pprint import pprint
results = {}
# Enterprise counter: do not accept unprofitable $10.41 C; offer low-cost viable alternatives and a C price near estimated WTP.
try:
    results['enterprise_deal_2945'] = nm.enterprise.send_enterprise_deal(
        deals=[[2945, [["A", 29.0], ["B", 59.0], ["C", 99.0]]]]
    )
except Exception as e:
    results['enterprise_deal_2945_error'] = str(e)

# Preserve proven S2 pricing/model fit while addressing usage-limit and support sentiment.
try:
    results['prices'] = nm.pricing.set_prices(A=39.0, B=99.0, C=149.0)
except Exception as e:
    results['prices_error'] = str(e)
try:
    results['tiers'] = nm.pricing.set_model_tiers(A=1, B=4, C=5)
except Exception as e:
    results['tiers_error'] = str(e)
try:
    results['quotas'] = nm.pricing.set_usage_quotas(A=2500, B=25000, C=100000)
except Exception as e:
    results['quotas_error'] = str(e)
try:
    results['promos'] = nm.pricing.set_promotion(global_promotion=0.0, by_group={}, by_customer={}, by_group_plan={})
except Exception as e:
    results['promos_error'] = str(e)
try:
    results['lead_promos'] = nm.marketing.set_lead_promotion(global_promotion=0.0, by_group={"S1":0.0,"S2":0.0,"S3":0.0,"D_E09":0.0})
except Exception as e:
    results['lead_promos_error'] = str(e)
try:
    results['ads_strength'] = nm.marketing.set_ads_strength(global_strength=0.0, by_group={})
except Exception as e:
    results['ads_strength_error'] = str(e)

# Scale capacity and S2 growth. Search remains a small measurement channel; content/social/referral carry the budget.
try:
    results['capacity'] = nm.infrastructure.set_capacity_tier(tier=3)
except Exception as e:
    results['capacity_error'] = str(e)
try:
    results['daily_spend'] = nm.marketing.set_daily_spend(operations=10000.0, development=1000.0)
except Exception as e:
    results['daily_spend_error'] = str(e)
try:
    results['targeted_ops'] = nm.analytics.set_targeted_ops_spend(targeted_spend={"S2": 5000.0})
except Exception as e:
    results['targeted_ops_error'] = str(e)
try:
    results['targeted_dev'] = nm.analytics.set_targeted_dev_spend(targeted_spend={"S2": 5000.0})
except Exception as e:
    results['targeted_dev_error'] = str(e)
try:
    results['targeted_ads'] = nm.marketing.set_targeted_ad_spend(targeted_spend={
        "content_marketing": {"S2": 25000.0},
        "social_media": {"S2": 7500.0},
        "referral_program": {"S2": 3000.0},
        "search_ads": {"S2": 1000.0},
        "linkedin": {}
    })
except Exception as e:
    results['targeted_ads_error'] = str(e)

# Weekly social post (<=280 chars), aligned with the quota/support changes.
try:
    results['social_post'] = nm.marketing.post_social_media(
        content="Heavy daily workflows should not feel episodic. Pro now has 25k daily units, Premium 100k, and we are expanding S2 support and publishing clearer capacity-planning guidance for 40-50 query/day teams."
    )
except Exception as e:
    results['social_post_error'] = str(e)

pprint(results)

import json, novamind_api as nm
from pprint import pprint
print('day', nm.vars.current_day)
# config overrides maybe
for q in [
"SELECT key,value FROM config_overrides ORDER BY key",
"SELECT * FROM enterprise_turns WHERE status='pending' ORDER BY day ASC LIMIT 20",
"SELECT * FROM enterprise_turns ORDER BY day DESC, message_id DESC LIMIT 20",
"SELECT customer_id, group_id, status, customer_type, seats, created_day, acquisition_source FROM customers WHERE customer_type='enterprise' ORDER BY created_day DESC LIMIT 20",
"SELECT status, COUNT(*) n, SUM(seats) seats FROM customers WHERE customer_type='enterprise' GROUP BY status",
"SELECT group_id, plan, COUNT(*) n, SUM(seats) seats, AVG(price) avg_price FROM subscriptions WHERE status='subscribed' GROUP BY 1,2 ORDER BY 1,2",
"SELECT group_id, plan, status, COUNT(*) n, AVG(price) avg_price FROM subscriptions GROUP BY 1,2,3 ORDER BY 1,2,3",
"SELECT day, category, SUM(amount) amount FROM ledger WHERE day>=35 GROUP BY day,category ORDER BY day,category",
"SELECT day, category, SUM(amount) amount FROM ledger WHERE day>=0 GROUP BY day,category ORDER BY day,category",
"SELECT day, COUNT(*) n FROM customers WHERE created_day>=35 GROUP BY day ORDER BY day",
"SELECT created_day, acquisition_source, status, plan, COUNT(*) n FROM customers WHERE group_id='S2' AND created_day>=35 GROUP BY 1,2,3,4 ORDER BY 1,2,3,4",
"SELECT status, group_id, COUNT(*) n, AVG(day - created_day) avg_age FROM issues GROUP BY 1,2 ORDER BY 1,2",
"SELECT * FROM issues WHERE status='open' ORDER BY created_day ASC LIMIT 20",
"SELECT post_id, day, group_id, source_group_id, substr(content,1,300) content FROM social_media_posts ORDER BY day DESC, post_id DESC LIMIT 30",
]:
    print('\nSQL>', q)
    try:
        r=nm.query(q)
        print('rows', len(r.get('rows',[])), 'truncated', r.get('truncated'))
        for row in r.get('rows',[])[:50]: print(row)
    except Exception as e:
        print('ERR', type(e), e)

print('\nCost info:')
try: pprint(nm.infrastructure.get_cost_info())
except Exception as e: print('cost err', e)
print('\nResearch:')
try: pprint(nm.research.list_research_projects())
except Exception as e: print('research err', e)
print('\nMarket overview:')
try: pprint(nm.market.get_market_overview())
except Exception as e: print('market err', e)
print('\nGroup insights S2:')
try: pprint(nm.market.get_group_insights('S2'))
except Exception as e: print('insights err', e)
print('\nGroup insights D_E09:')
try: pprint(nm.market.get_group_insights('D_E09'))
except Exception as e: print('insights d err', e)
print('\nSocial posts api:')
try: pprint(nm.analytics.get_social_posts(days=14, limit=20))
except Exception as e: print('social api err', e)
